+    /// use ruvector_rulake_kernel_wgpu::WgpuKernel;
+    /// let _ = WgpuKernel::new_async().await;
+    /// # }
+    /// ```
+    pub async fn new_async() -> Result<Self, WgpuKernelError> {
+        let instance = wgpu::Instance::new(wgpu::InstanceDescriptor::default());
